import dataclasses
import typing
import json


def dataclass_to_dict(obj):
    if not dataclasses.is_dataclass(obj):
        return obj
    return dataclasses.asdict(obj)

def dataclass_from_dict(klass, dikt):
    if not dataclasses.is_dataclass(klass):
        return dikt

    if not isinstance(dikt, dict):
        return klass(dikt)

    fieldtypes = {f.name:f.type for f in dataclasses.fields(klass)}

    args = {}
    for field in dataclasses.fields(klass):
        field_name = field.name
        field_type = fieldtypes[field_name]

        if field_name in dikt:
            val = dikt[field_name]
            if dataclasses.is_dataclass(field_type):
                args[field_name] = dataclass_from_dict(field_type, val)
            elif typing.get_origin(field_type) is list:
                 # Handle lists of dataclasses
                list_type = typing.get_args(field_type)[0]
                if dataclasses.is_dataclass(list_type):
                    args[field_name] = [dataclass_from_dict(list_type, item) for item in val]
                else:
                    args[field_name] = val
            else:
                args[field_name] = val

    return klass(**args)

def serialize_dataclass(obj):
    return json.dumps(dataclass_to_dict(obj))

def deserialize_dataclass(json_str, klass):
    return dataclass_from_dict(klass, json.loads(json_str))


if __name__ == '__main__':
    @dataclasses.dataclass
    class Inner:
        x: int
        y: str

    @dataclasses.dataclass
    class Outer:
        a: int
        b: Inner
        c: typing.List[Inner]

    # Example Usage
    inner1 = Inner(x=1, y="hello")
    inner2 = Inner(x=2, y="world")
    outer = Outer(a=10, b=inner1, c=[inner1, inner2])

    # Serialization
    serialized_data = serialize_dataclass(outer)
    print("Serialized:", serialized_data)

    # Deserialization
    deserialized_outer = deserialize_dataclass(serialized_data, Outer)
    print("Deserialized:", deserialized_outer)

    # Verification
    print("Are equal:", outer == deserialized_outer)
